function calculate() {
    let score = 0;
    const maxScore = 50;

    // 1. Food and Water (max 7 points, 1 point per day up to 7, min 0 for 0 days)
    score += Math.min(Number(daysFoodWater), 7);

    // 2. Alternative Heat (0, 4, 8 points)
    if (Number(alternativeHeat) === 1) score += 4;
    if (Number(alternativeHeat) === 2) score += 8;

    // 3. Power Backup (0, 3, 6 points)
    if (Number(powerBackup) === 1) score += 3;
    if (Number(powerBackup) === 2) score += 6;

    // 4. Communication Plan (0, 5 points)
    if (Number(commPlan) === 1) score += 5;

    // 5. First Aid & Knowledge (0, 5 points)
    if (Number(firstAidKnowledge) === 1) score += 5;

    // 6. Home Safeguards (0, 3, 6 points)
    if (Number(homeSafeguards) === 1) score += 3;
    if (Number(homeSafeguards) === 2) score += 6;

    // 7. Vehicle Readiness (0, 2, 4 points)
    if (Number(vehicleReadiness) === 1) score += 2;
    if (Number(vehicleReadiness) === 2) score += 4;

    // 8. Local Alert Awareness (0, 4 points)
    if (Number(localAlertAwareness) === 1) score += 4;

    // 9. Emergency Cash (0, 3 points)
    if (Number(cashSupply) === 1) score += 3;

    // 10. Pet Preparedness (0, 1.5, 3 points, only if pets exist)
    if (Number(petPreparedness) === 1) score += 1.5;
    if (Number(petPreparedness) === 2) score += 3;

    let preparednessScore = (score / maxScore) * 100;
    preparednessScore = Math.max(0, Math.min(100, preparednessScore)); // Cap between 0 and 100

    let readinessLevel;
    if (preparednessScore < 25) {
        readinessLevel = 'Critical: Immediate Action Needed';
    } else if (preparednessScore <= 50) {
        readinessLevel = 'Developing: Significant Improvement Recommended';
    } else if (preparednessScore <= 75) {
        readinessLevel = 'Prepared: Good Foundation, Room for Enhancement';
    } else if (preparednessScore <= 90) {
        readinessLevel = 'Highly Prepared: Resilient and Ready';
    } else {
        readinessLevel = 'Exemplary: A Leader in Preparedness';
    }

    return {
        preparednessScore: preparednessScore,
        readinessLevel: readinessLevel
    };
}
